content.content:
body { font-family: system-ui, sans-serif; margin: 40px; }
.layout { display: grid; grid-template-columns: 1fr 1fr; gap: 16px; max-width: 960px; }
.card { padding: 16px; border: 1px solid #ddd; border-radius: 12px; }
.muted { color: #666; }
.lista { list-style: none; padding: 0; margin: 0; }
.lista li { padding: 10px 12px; border: 1px solid #eee; border-radius: 10px; margin-bottom: 8px; cursor: pointer; }
.lista li.ativo { border-color: #999; }
.row { margin-top: 12px; }
label { display: grid; gap: 6px; }
input { padding: 10px 12px; border: 1px solid #ddd; border-radius: 10px; }
.buttons { display: flex; gap: 10px; }
button { padding: 10px 12px; cursor: pointer; }
.pill { display: inline-block; padding: 6px 10px; border: 1px solid #ddd; border-radius: 999px; }

'use strict';

// ============================
// Estado (dados)
// ============================
const itens = [
  { id: 1, nome: 'Arroz', qtd: 2 },
  { id: 2, nome: 'Feijão', qtd: 1 },
  { id: 3, nome: 'Café', qtd: 3 },
];

// Seleção por ID (não guardamos o objeto inteiro como fonte de verdade)
let selectedId = null;

// Buffer de edição (separar edição de dados persistidos)
let draft = { nome: '', qtd: 0 };

// ============================
// DOM
// ============================
function assertEl(selector) {
  const el = document.querySelector(selector);
  if (el === null) console.error(`[lista] elemento não encontrado: ${selector}`);
  return el;
}

const elLista = assertEl('#lista');
const elNome = assertEl('#nome');
const elQtd = assertEl('#qtd');
const btnSalvar = assertEl('#salvar');
const btnDesfazer = assertEl('#desfazer');
const elStatus = assertEl('#status');

const hasDom = Boolean(elLista && elNome && elQtd && btnSalvar && btnDesfazer && elStatus);
if (!hasDom) {
  console.warn('[lista] inicialização abortada por DOM incompleto.');
}

// ============================
// Utilitários de tipo/validação
// ============================
function toInt(value) {
  const n = Number(value);
  if (Number.isNaN(n)) return 0;
  return Math.max(0, Math.trunc(n));
}

function findItemById(id) {
  return itens.find((it) => it.id === id) || null;
}

// ============================
// Render
// ============================
function renderLista() {
  if (!hasDom) return;

  elLista.innerHTML = '';

  for (const it of itens) {
    const li = document.createElement('li');
    li.textContent = `${it.nome} — qtd: ${it.qtd}`;

    if (it.id === selectedId) li.classList.add('ativo');

    li.addEventListener('click', () => {
      selectById(it.id);
    });

    elLista.appendChild(li);
  }
}

function renderDetalhes() {
  if (!hasDom) return;

  if (selectedId === null) {
    elNome.value = '';
    elQtd.value = '';
    elNome.disabled = true;
    elQtd.disabled = true;
    elStatus.textContent = 'Nenhum selecionado';
    return;
  }

  elNome.disabled = false;
  elQtd.disabled = false;

  elNome.value = draft.nome;
  elQtd.value = String(draft.qtd);

  const it = findItemById(selectedId);
  elStatus.textContent = it ? `Selecionado: #${it.id}` : 'Selecionado: (não encontrado)';
}

function render() {
  renderLista();
  renderDetalhes();
}

// ============================
// Ações (mudança de estado)
// ============================
function selectById(id) {
  selectedId = id;

  // Importante: draft é cópia de valores (primitivos), não referência ao objeto
  const it = findItemById(id);
  if (it) {
    draft = { nome: it.nome, qtd: it.qtd };
  } else {
    draft = { nome: '', qtd: 0 };
  }

  render();
}

function updateDraftFromInputs() {
  draft = {
    nome: String(elNome.value).trim(),
    qtd: toInt(elQtd.value),
  };
}

function salvar() {
  if (selectedId === null) return;

  updateDraftFromInputs();

  if (draft.nome.length === 0) {
    console.warn('[lista] nome vazio: não vou salvar');
    return;
  }

  const it = findItemById(selectedId);
  if (!it) {
    console.warn('[lista] item não encontrado: não vou salvar');
    return;
  }

  // Mutação controlada: altera apenas o item selecionado
  it.nome = draft.nome;
  it.qtd = draft.qtd;

  render();
}

function desfazer() {
  if (selectedId === null) return;

  const it = findItemById(selectedId);
  if (!it) return;

  // Volta o draft para o estado persistido
  draft = { nome: it.nome, qtd: it.qtd };
  render();
}

// ============================
// Eventos
// ============================
function wire() {
  if (!hasDom) return;

  btnSalvar.addEventListener('click', salvar);
  btnDesfazer.addEventListener('click', desfazer);

  // Atualiza draft enquanto digita (apenas em memória)
  elNome.addEventListener('input', () => {
    updateDraftFromInputs();
    renderDetalhes();
  });

  elQtd.addEventListener('input', () => {
    updateDraftFromInputs();
    renderDetalhes();
  });
}

// ============================
// Bootstrap
// ============================
wire();
render();
console.log('[lista] pronto');
